from __future__ import annotations

import base64
import gzip
import subprocess
from pathlib import Path

PATCH_B64 = ''
patch_path = Path('.agent/daily_limit_scan_scope.patch')
patch_path.write_bytes(gzip.decompress(base64.b64decode(PATCH_B64)))
subprocess.run(['git', 'apply', '--check', str(patch_path)], check=True)
subprocess.run(['git', 'apply', str(patch_path)], check=True)
patch_path.unlink(missing_ok=True)
